import React, { useState, useEffect } from 'react';
import './App.css';
import Topo from './components/Topo';
import Rodape from './components/Rodape'; // Importe aqui

function App() {
  const [produtos, setProdutos] = useState([]);
  const [carrinho, setCarrinho] = useState([]);
  const [verCarrinho, setVerCarrinho] = useState(false);

  useEffect(() => {
    fetch("http://localhost:3001/produtos")
      .then(res => res.json())
      .then(dados => setProdutos(dados))
      .catch(err => console.error(err));
  }, []);

  const adicionarAoCarrinho = (produto) => {
    const existe = carrinho.find(x => x.id === produto.id);
    if (existe) {
      setCarrinho(carrinho.map(x => x.id === produto.id ? { ...existe, qtd: existe.qtd + 1 } : x));
    } else {
      setCarrinho([...carrinho, { ...produto, qtd: 1 }]);
    }
  };

  const alterarQtd = (id, operacao) => {
    setCarrinho(carrinho.map(item => {
      if (item.id === id) {
        const novaQtd = operacao === '+' ? item.qtd + 1 : item.qtd - 1;
        return { ...item, qtd: novaQtd > 0 ? novaQtd : 1 };
      }
      return item;
    }));
  };

  const totalGeral = carrinho.reduce((acc, item) => acc + (item.valor * item.qtd), 0);

  if (verCarrinho) {
    return (
      <div className="App">
        <Topo totalItens={carrinho.length} abrirCarrinho={() => setVerCarrinho(true)} />
        <div style={{padding: '20px'}}>
          <h2>Seu Pedido</h2>
          {carrinho.map(item => (
            <div key={item.id} style={{borderBottom: '1px solid #ccc', padding: '10px', display: 'flex', justifyContent: 'space-between'}}>
              <span>{item.produto}</span>
              <div>
                <button onClick={() => alterarQtd(item.id, '-')}>-</button>
                <span style={{margin: '0 10px'}}>{item.qtd}</span>
                <button onClick={() => alterarQtd(item.id, '+')}>+</button>
              </div>
              <span>R$ {(item.valor * item.qtd).toFixed(2)}</span>
            </div>
          ))}
          <h3>Total: R$ {totalGeral.toFixed(2)}</h3>
          <button onClick={() => setVerCarrinho(false)}>Voltar às Compras</button>
          <button style={{backgroundColor: 'green', color: 'white', marginLeft: '10px'}} onClick={() => alert('Pedido Fechado!')}>Fechar Pedido</button>
        </div>
      </div>
    );
  }

  return (
    <div className="App">
      <Topo totalItens={carrinho.length} abrirCarrinho={() => setVerCarrinho(true)} />
      <div className="grid-produtos">
        {produtos.map((item) => (
          <div key={item.id} className="card">
            <img src={item.imagem_url} alt={item.produto} />
            <h3>{item.produto}</h3>
            <p className="preco">R$ {parseFloat(item.valor).toFixed(2)}</p>
            <button onClick={() => adicionarAoCarrinho(item)}>Comprar</button>
          </div>
        ))}
        </div>
      <div className='rodape-content ' >
      <Rodape/>
    
    </div>
     
    </div>
  );
}

export default App;
